    .{ .name = "gf-neg", .signature = "(gf-neg a)", .summary = "Negation" },
    .{ .name = "latex", .signature = "(latex expr)", .summary = "Convert to LaTeX string" },
};

const std = @import("std");

/// Looks up documentation for a builtin or special form by name.
pub fn find(name: []const u8) ?Doc {
    for (docs) |doc| {
        if (std.mem.eql(u8, doc.name, name)) return doc;
    }
    return null;
}
